import{_ as a,o as i,c as t,a2 as o}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"Configurazione","description":"","frontmatter":{},"headers":[],"relativePath":"it/guide/configuration.md","filePath":"it/guide/configuration.md"}'),d={name:"it/guide/configuration.md"};function n(s,e,r,l,c,p){return i(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h1><p>Clearance viene fornito con impostazioni predefinite sensate, quindi funziona out of the box dopo l&#39;<a href="/clearance-docs/it/guide/installation.html">installazione</a>. Pubblica il file di configurazione quando devi personalizzare il prefisso delle route, il middleware, i modelli contestuali o qualsiasi altra impostazione.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Questo pubblica <code>config/clearance.php</code>.</p><h2 id="riferimento-di-configurazione" tabindex="-1">Riferimento di configurazione <a class="header-anchor" href="#riferimento-di-configurazione" aria-label="Permalink to &quot;Riferimento di configurazione&quot;">​</a></h2><p>Questo è il riferimento definitivo per ogni chiave in <code>config/clearance.php</code>. Le altre pagine di questa documentazione rimandano qui invece di ripetere la tabella.</p><table tabindex="0"><thead><tr><th>Chiave</th><th>Predefinito</th><th>Scopo</th></tr></thead><tbody><tr><td><code>route_prefix</code></td><td><code>&#39;clearance&#39;</code></td><td>Prefisso URI per tutte le route del pannello.</td></tr><tr><td><code>middleware</code></td><td><code>[&#39;web&#39;, &#39;auth&#39;]</code></td><td>Applicato a tutte le route del pannello prima di <code>clearance.access</code>.</td></tr><tr><td><code>access_permission</code></td><td><code>&#39;clearance-access&#39;</code></td><td>Permesso verificato dal middleware di accesso.</td></tr><tr><td><code>user_model</code></td><td><code>null</code></td><td>Il valore predefinito è <code>auth.providers.users.model</code>.</td></tr><tr><td><code>modules.users</code></td><td><code>false</code></td><td>Interruttore principale per il modulo Utenti (route + componenti Livewire).</td></tr><tr><td><code>contextual_models</code></td><td><code>[]</code></td><td><code>FQCN =&gt; [&#39;label&#39;, &#39;icon&#39;, &#39;label_attribute&#39;, &#39;searchable&#39;]</code> - modelli che possono fungere da contesti di binding per i ruoli.</td></tr><tr><td><code>enforce_naming_convention</code></td><td><code>true</code></td><td>Applica la convenzione di naming <code>group-action</code> per i permessi.</td></tr><tr><td><code>naming_separator</code></td><td><code>&#39;-&#39;</code></td><td>Carattere separatore - solo <code>&#39;-&#39;</code> o <code>&#39;_&#39;</code>.</td></tr><tr><td><code>guards</code></td><td><code>[]</code></td><td>Sovrascrive le guardie rilevate automaticamente da <code>config/auth.php</code>. Vuoto = rileva automaticamente tutte.</td></tr><tr><td><code>allowed_guard_drivers</code></td><td><code>[&#39;session&#39;, &#39;token&#39;, &#39;jwt&#39;, &#39;passport&#39;, &#39;sanctum&#39;]</code></td><td>Driver accettati durante l&#39;iniezione delle guardie basate su database in <code>auth.guards</code>.</td></tr><tr><td><code>layout</code></td><td><code>null</code></td><td>Layout Blade per i componenti a pagina intera. <code>null</code> = predefinito dell&#39;app ospitante (<code>config(&#39;livewire.layout&#39;)</code>).</td></tr><tr><td><code>auto_assign_default_role</code></td><td><code>false</code></td><td>Assegna automaticamente il ruolo predefinito configurato nelle Impostazioni all&#39;evento <code>Registered</code>.</td></tr><tr><td><code>super_admin_gate_bypass</code></td><td><code>false</code></td><td>Opzionale: <code>super_admin</code> bypassa tutti i controlli Gate a livello di applicazione.</td></tr><tr><td><code>ui.flux_pro</code></td><td><code>null</code></td><td><code>null</code> = rilevamento automatico tramite <code>Flux::pro()</code>.</td></tr></tbody></table><h2 id="convenzione-di-naming-dei-permessi" tabindex="-1">Convenzione di naming dei permessi <a class="header-anchor" href="#convenzione-di-naming-dei-permessi" aria-label="Permalink to &quot;Convenzione di naming dei permessi&quot;">​</a></h2><p>I permessi devono seguire il formato <code>group-action</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>Disabilita l&#39;applicazione per ambiente con <code>enforce_naming_convention</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Il separatore viene validato all&#39;avvio</p><p>Il valore di <code>naming_separator</code> è l&#39;unica parte di questa configurazione che raggiunge un frammento SQL grezzo (raggruppamento/ordinamento dei permessi), quindi sono accettati solo <code>-</code> o <code>_</code>.</p></div><h2 id="personalizzare-il-middleware" tabindex="-1">Personalizzare il middleware <a class="header-anchor" href="#personalizzare-il-middleware" aria-label="Permalink to &quot;Personalizzare il middleware&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;middleware&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;web&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>I nomi delle route restano stabili indipendentemente dalle modifiche al prefisso o al middleware - vedi la <a href="/clearance-docs/it/guide/quick-start.html">Guida Rapida</a> per la tabella completa delle route.</p><h2 id="correlati" tabindex="-1">Correlati <a class="header-anchor" href="#correlati" aria-label="Permalink to &quot;Correlati&quot;">​</a></h2><ul><li><a href="/clearance-docs/it/guide/quick-start.html">Guida Rapida</a> - montare il pannello con queste impostazioni applicate</li><li><a href="/clearance-docs/it/guide/publishing.html">Pubblicazione degli asset</a> - pubblicare le traduzioni e capire la chiave <code>layout</code></li><li><a href="/clearance-docs/it/features/guards.html">Guardie</a> - come vengono usate <code>guards</code> e <code>allowed_guard_drivers</code></li><li><a href="/clearance-docs/it/features/super-admin.html">Super Admin</a> - come funziona <code>super_admin_gate_bypass</code></li></ul>`,18)])])}const g=a(d,[["render",n]]);export{h as __pageData,g as default};
